def lengthOfLongestSubstring(s):
    seen = {}
    l = 0
    res = 0
    for r, char in enumerate(s):
        if char in seen and seen[char] >= l:
            # Slide left pointer past the duplicate occurrence
            l = seen[char] + 1
        seen[char] = r
        res = max(res, r - l + 1)
    return res

