int lengthOfLongestSubstring(string s) {
    vector<int> seen(256, -1); // ASCII lookup
    int l = 0, res = 0;
    for (int r = 0; r < s.size(); ++r) {
        if (seen[s[r]] >= l) {
            l = seen[s[r]] + 1;
        }
        seen[s[r]] = r;
        res = max(res, r - l + 1);
    }
    return res;
}

