def characterReplacement(s, k):
    count = {}
    l = 0
    max_f = 0
    for r in range(len(s)):
        count[s[r]] = count.get(s[r], 0) + 1
        max_f = max(max_f, count[s[r]])

        # Window size - max_f is the number of changes needed
        if (r - l + 1) - max_f > k:
            count[s[l]] -= 1
            l += 1

    return (r - l + 1)

