int characterReplacement(string s, int k) {
    int count[26] = {0};
    int l = 0, max_f = 0;
    int r = 0;
    for (r = 0; r < s.size(); ++r) {
        count[s[r] - 'A']++;
        max_f = max(max_f, count[s[r] - 'A']);

        if ((r - l + 1) - max_f > k) {
            count[s[l] - 'A']--;
            l++;
        }
    }
    return s.size() - l;
}

int minSubArrayLen(int target, vector<int>& nums) {
    int l = 0, curr_sum = 0, res = INT_MAX;
    for (int r = 0; r < nums.size(); ++r) {
        curr_sum += nums[r];
        while (curr_sum >= target) {
            res = min(res, r - l + 1);
            curr_sum -= nums[l++];
        }
    }
    return res == INT_MAX ? 0 : res;
}

