string minWindow(string s, string t) {
    if (s.empty() || t.empty()) return "";
    vector<int> dictT(128, 0);
    for (char c : t) dictT[c]++;

    vector<int> window(128, 0);
    int have = 0, need = 0;
    for (int count : dictT) if (count > 0) need++;

    int l = 0, min_l = 0, min_len = INT_MAX;
    for (int r = 0; r < s.size(); ++r) {
        char c = s[r];
        if (dictT[c] > 0) {
            window[c]++;
            if (window[c] == dictT[c]) have++;
        }

        while (have == need) {
            if (r - l + 1 < min_len) {
                min_len = r - l + 1;
                min_l = l;
            }
            char left_char = s[l];
            if (dictT[left_char] > 0) {
                window[left_char]--;
                if (window[left_char] < dictT[left_char]) have--;
            }
            l++;
        }
    }
    return min_len == INT_MAX ? "" : s.substr(min_l, min_len);
}

