def subarraysWithKDistinct(nums, k):
    def atMost(limit):
        count = {}
        l = 0
        subarrays = 0
        for r in range(len(nums)):
            if nums[r] not in count:
                count[nums[r]] = 0
            count[nums[r]] += 1

            while len(count) > limit:
                count[nums[l]] -= 1
                if count[nums[l]] == 0:
                    del count[nums[l]]
                l += 1
            subarrays += r - l + 1
        return subarrays

    return atMost(k) - atMost(k - 1)

cppCode:
int subarraysWithKDistinct(vector<int>& nums, int k) {
    auto atMost = [&](int limit) -> int {
        unordered_map<int, int> count;
        int l = 0, subarrays = 0;
        for (int r = 0; r < nums.size(); ++r) {
            count[nums[r]]++;
            while (count.size() > limit) {
                count[nums[l]]--;
                if (count[nums[l]] == 0) {
                    count.erase(nums[l]);
                }
                l++;
            }
            subarrays += r - l + 1;
        }
        return subarrays;
    };
    return atMost(k) - atMost(k - 1);
}
